const body = $input.first().json.body;
const pr = body.pull_request;

if (!pr) {
  throw new Error('No pull_request object found in webhook payload');
}

return [{
  json: {
    prNumber: pr.number,
    repo: body.repository.full_name,
    repoOwner: body.repository.full_name.split('/')[0],
    repoName: body.repository.full_name.split('/')[1],
    author: pr.user.login,
    title: pr.title,
    description: pr.body || '',
    diffUrl: pr.diff_url,
    sha: pr.head.sha,
    branch: pr.head.ref,
    baseBranch: pr.base.ref,
    additions: pr.additions || 0,
    deletions: pr.deletions || 0,
    changedFiles: pr.changed_files || 0,
    htmlUrl: pr.html_url,
    timestamp: new Date().toISOString(),
    startTime: Date.now()
  }
}];

const items = $input.all();

function parseGeminiResponse(item) {
  try {
    if (!item || !item.json) {
      return { score: 50, severity: 'medium', findings: [], summary: 'No data received' };
    }
    const d = item.json;
    if (d.candidates && d.candidates[0] && d.candidates[0].content) {
      const text = d.candidates[0].content.parts[0].text;
      return JSON.parse(text);
    }
    if (d.score !== undefined) return d;
    if (typeof d.content === 'string') return JSON.parse(d.content);
    return { score: 50, severity: 'medium', findings: [], summary: 'Unexpected response format' };
  } catch (e) {
    return { score: 50, severity: 'medium', findings: [], summary: 'Parse error: ' + e.message };
  }
}

const security = parseGeminiResponse(items[0]);
const performance = parseGeminiResponse(items[1]);
const practices = parseGeminiResponse(items[2]);

const compositeScore = Math.round(
  (security.score * 0.4) +
  (performance.score * 0.3) +
  (practices.score * 0.3)
);

let verdict;
if (compositeScore >= 80) verdict = 'APPROVE';
else if (compositeScore >= 50) verdict = 'REQUEST_CHANGES';
else verdict = 'REJECT';

// Collect all findings with category
const allRaw = [
  ...(security.findings || []).map(f => ({ ...f, category: 'security' })),
  ...(performance.findings || []).map(f => ({ ...f, category: 'performance' })),
  ...(practices.findings || []).map(f => ({ ...f, category: 'practices' }))
];

// Deduplicate by file + line + type (keep highest severity)
const severityRank = { critical: 4, high: 3, medium: 2, low: 1 };
const seen = new Map();

for (const f of allRaw) {
  const key = (f.file || '') + ':' + String(f.line || '').replace(/[^0-9,-]/g, '');
  const existing = seen.get(key);
  if (!existing || (severityRank[f.severity] || 0) > (severityRank[existing.severity] || 0)) {
    seen.set(key, f);
  }
}

const allFindings = Array.from(seen.values());
const criticalCount = allFindings.filter(f => f.severity === 'critical').length;
const highCount = allFindings.filter(f => f.severity === 'high').length;
const dedupedCount = allRaw.length - allFindings.length;

if (criticalCount > 0 && (security.findings || []).some(f => f.severity === 'critical')) {
  verdict = 'REJECT';
}

const prData = $node['Extract PR Data'].json;
const executionTime = Date.now() - prData.startTime;

return [{
  json: {
    prNumber: prData.prNumber,
    repo: prData.repo,
    repoOwner: prData.repoOwner,
    repoName: prData.repoName,
    author: prData.author,
    title: prData.title,
    branch: prData.branch,
    baseBranch: prData.baseBranch,
    sha: prData.sha,
    htmlUrl: prData.htmlUrl,
    securityScore: security.score,
    performanceScore: performance.score,
    practicesScore: practices.score,
    compositeScore: compositeScore,
    verdict: verdict,
    securityFindings: (security.findings || []),
    performanceFindings: (performance.findings || []),
    practicesFindings: (practices.findings || []),
    securitySummary: security.summary,
    performanceSummary: performance.summary,
    practicesSummary: practices.summary,
    totalFindings: allFindings.length,
    duplicatesRemoved: dedupedCount,
    criticalCount: criticalCount,
    highCount: highCount,
    executionTimeMs: executionTime,
    reviewBody: '## AI Code Review - Score: ' + compositeScore + '/100 (' + verdict + ')\n\n' +
      '| Category | Score | Findings |\n|---|---|---|\n' +
      '| Security | ' + security.score + '/100 | ' + (security.findings || []).length + ' |\n' +
      '| Performance | ' + performance.score + '/100 | ' + (performance.findings || []).length + ' |\n' +
      '| Best Practices | ' + practices.score + '/100 | ' + (practices.findings || []).length + ' |\n\n' +
      '### Security\n' + security.summary + '\n\n' +
      '### Performance\n' + performance.summary + '\n\n' +
      '### Best Practices\n' + practices.summary + '\n\n' +
      (criticalCount > 0 ? '**' + criticalCount + ' CRITICAL finding(s) detected.**\n\n' : '') +
      '### Findings (' + allFindings.length + ' unique' + (dedupedCount > 0 ? ', ' + dedupedCount + ' duplicates removed' : '') + ')\n\n' +
      allFindings.filter(f => f.severity === 'critical' || f.severity === 'high').map(f =>
        '- **[' + f.severity.toUpperCase() + '] [' + f.category + ']** ' + f.file + ':' + f.line + ' - ' + f.description
      ).join('\n') +
      '\n\n---\n*Automated review by AI Code Review Pipeline*'
  }
}];

