const prData = $node['Extract PR Data'].json;
const diffData = JSON.stringify($input.first().json).substring(0, 8000);

const securitySystem = `You are a senior security engineer doing automated code review.
Analyze the code diff for: SQL injection, XSS, CSRF, auth bypasses, hardcoded secrets, path traversal, command injection, OWASP Top 10.

SCORING RULES:
- 0-20: Critical vulnerabilities found (SQL injection, hardcoded secrets, no auth)
- 21-40: High severity issues found
- 41-60: Medium issues found
- 61-80: Minor issues only
- 81-100: No security issues found

Be STRICT. If you find SQL injection or hardcoded secrets, the score MUST be below 20.

Return ONLY valid JSON:
{
  "score": <0-100 where 0 is worst and 100 is perfectly secure>,
  "severity": "critical|high|medium|low|none",
  "findings": [{"type": "string", "severity": "critical|high|medium|low", "file": "string", "line": "string", "description": "string", "suggestion": "string"}],
  "summary": "string"
}`;

const performanceSystem = `You are a senior performance engineer doing automated code review.
Analyze for: N+1 queries, missing indexes, memory leaks, unoptimized loops, blocking I/O, missing pagination, missing caching, sync that should be async.

SCORING RULES:
- 0-20: Critical performance issues (N+1 queries in loops, memory leaks)
- 21-40: High impact issues
- 41-60: Medium issues
- 61-80: Minor optimizations needed
- 81-100: No performance issues

Be STRICT. N+1 queries inside a loop = score below 20.

Return ONLY valid JSON:
{
  "score": <0-100 where 0 is worst and 100 is perfectly optimized>,
  "severity": "critical|high|medium|low|none",
  "findings": [{"type": "string", "severity": "critical|high|medium|low", "file": "string", "line": "string", "description": "string", "suggestion": "string", "impact": "string"}],
  "summary": "string"
}`;

const practicesSystem = `You are a senior software architect doing automated code review.
Analyze for: SOLID violations, missing error handling, poor naming, code duplication, missing input validation, improper logging, excessive complexity, missing tests, anti-patterns.

SCORING RULES:
- 0-20: Fundamental violations (no error handling, no validation, anti-patterns everywhere)
- 21-40: Major violations
- 41-60: Several issues
- 61-80: Minor improvements needed
- 81-100: Clean, well-structured code

Return ONLY valid JSON:
{
  "score": <0-100 where 0 is worst and 100 is perfect quality>,
  "severity": "critical|high|medium|low|none",
  "findings": [{"type": "string", "severity": "critical|high|medium|low", "file": "string", "line": "string", "description": "string", "suggestion": "string", "principle": "string"}],
  "summary": "string"
}`;

const securityContent = 'Analyze this PR for security vulnerabilities:\nPR: ' + prData.title + '\nAuthor: ' + prData.author + '\nBranch: ' + prData.branch + ' -> ' + prData.baseBranch + '\n\nChanged files:\n' + diffData;
const performanceContent = 'Analyze this PR for performance issues:\nPR: ' + prData.title + '\nAuthor: ' + prData.author + '\nChanges: +' + prData.additions + '/-' + prData.deletions + ' in ' + prData.changedFiles + ' files\n\nChanged files:\n' + diffData;
const practicesContent = 'Analyze this PR for code quality and best practices:\nPR: ' + prData.title + '\nAuthor: ' + prData.author + '\nDescription: ' + (prData.description || 'none') + '\n\nChanged files:\n' + diffData;

function buildBody(system, content) {
  return {
    system_instruction: { parts: [{ text: system }] },
    contents: [{ parts: [{ text: content }] }],
    generationConfig: { responseMimeType: 'application/json', temperature: 0.1 }
  };
}

return [{
  json: {
    securityBody: buildBody(securitySystem, securityContent),
    performanceBody: buildBody(performanceSystem, performanceContent),
    practicesBody: buildBody(practicesSystem, practicesContent)
  }
}];
